  ('locality-d0d1b9a2-moex-00044', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '甲機關於X3年1月10日接受乙機關行政委託監測空污情形，監測期間自2月1日至12月31日， 雙方協調乙機關於5月1日撥付委託款項。依中央政府普通公務單位會計制度之一致規定，針對 以上交易，甲機關所作分錄為何？', '["5月1日，借：專戶存款，貸：應付代收款", "1月10日，借：其他應收款，貸：應付代收款", "5月1日，借：公庫撥入數，貸：專戶存款", "1月10日，借：專戶存款，貸：應付代收款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "c27794c584bd", "answer_pdf_sha1": "276f68ff4258", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
